def max_sum_increasing_subseq(arr, n, k, i):
    max_sum = 0
    for j in range(i + 1, n):
        if arr[j] > arr[k]:
            max_sum = max(max_sum, arr[j])
    return max_sum + arr[k] + arr[i] - arr[k] - arr[i] + max_sum_increasing_subseq(arr, n, k, i) - arr[i] - arr[k] + arr[i] + arr[k] - 1

def sum_series(n):
