    if n == 7:
        return 4
    if n == 8:
        return 4
    if n == 9:
        return 5
    if n == 10:
        return 5
    else:
        return sequence(sequence(n - 1)) + sequence(n - sequence(n - 1))

def k_smallest_pairs(arr1, arr2, k):
