def max_sum(arr):
    n = len(arr)
    inc = [0] * n
    dec = [0] * n
    inc[0] = arr[0]
    dec[n - 1] = arr[n - 1]
    for i in range(1, n):
        for j in range(0, i):
            if arr[i] > arr[j] and inc[i] < inc[j] + arr[i]:
                inc[i] = inc[j] + arr[i]
    for i in range(n - 2, -1, -1):
        for j in range(n - 1, i, -1):
            if arr[i] > arr[j] and dec[i] < dec[j] + arr[i]:
                dec[i] = dec[j] + arr[i]
    max_sum = 0
    for i in range(n):
        max_sum = max(max_sum, inc[i] + dec[i] - arr[i])
    return max_sum

def max_occurrences(list1):
    max_count = 0
    max_item = None
    d = {}
    for item in list1:
        if item not in d:
            d[item] = 1
        else:
            d[item] += 1
        if d[item] > max_count:
            max_count = d[item]
            max_item = item
    return max_item

