def count_no_of_ways(n, k):
    dp = [[0 for i in range(k)] for j in range(n + 1)]
    dp[0][0] = 1
    dp[1][0] = 1
    dp[1][1] = 1
    dp[1][2] = 2
    dp[1][3] = 3
    for i in range(2, n):
        for j in range(k):
            dp[i][j] = 0
            for x in range(k):
                if x != j:
                    dp[i][j] += dp[i - 1][x]
    ans = 0
    for i in range(k):
        ans += dp[n - 1][i]
    return ans

