def rearrange_bigger(num):
    temp = list(str(num))
    i = len(temp) - 1
    while i > 0 and temp[i - 1] <= temp[i]:
        i -= 1
    if i <= 0:
        return -1
    j = len(temp) - 1
    while temp[j] <= temp[i - 1]:
        j -= 1
    temp[i - 1], temp[j] = temp[j], temp[i - 1]
    temp[i:] = temp[len(temp) - 1: i - 1: -1]
    return int(''.join(temp))

