def count_bidirectional(test_list):
    count = 0
    for i in test_list:
        for j in test_list:
            if (i[0] == j[1]) and (i[1] == j[0]):
                count += 1
    return count

def count_Occurrence(test_tup, test_list):
    result = 0
    for x in test_list:
        result += test_tup.count(x)
    return result

def remove_odd(numbers):
    result = []
    for number in numbers:
        if number % 2 == 0:
            result.append(number)
    return result
